+#[test]
+fn circuit_breaker_integration() {
+    let rt = RuntimeFixture::current_thread();
+    rt.block_on(async {
+        let policy = RetryPolicy {
+            initial_delay: Duration::from_millis(1),
+            max_delay: Duration::from_millis(10),
